class Solution:
    def exclusiveTime(self, n: int, logs: List[str]) -> List[int]:
        ans=[0]*n; st=[]; prev=0
        for log in logs:
            fid,typ,ts= log.split(":"); fid=int(fid); ts=int(ts)
            if typ=="start":
                if st: ans[st[-1]]+=ts-prev
                st.append(fid); prev=ts
            else:
                ans[st.pop()]+=ts-prev+1; prev=ts+1
        return ans

